// ── Shared HTTP headers ──────────────────────────────────────────────────────
const HEADERS = {
  'Content-Type': 'application/json',
  'Accept':       'application/json',
};

// ── Default function (called once per VU iteration) ─────────────────────────
export default function () {
  // __ITER is 0-based, maps directly to dataset index
  const row      = TEST_DATA[__ITER % TEST_DATA.length];
  const [sats, gcse, asGrade] = row.features;

  // Triton HTTP/REST inference request body (KServe v2 protocol)
  // max_batch_size: 0  → send shape [1, 3] explicitly
  const payload = JSON.stringify({
    id:     row.ref_id,
    inputs: [
      {
        name:     'input',
        shape:    [1, 3],
        datatype: 'FP32',
        data:     [[sats, gcse, asGrade]],
      },
    ],
    outputs: [
      { name: 'output_label' },
    ],
  });

  const res = http.post(INFER_URL, payload, { headers: HEADERS });

  // ── Record custom latency ────────────────────────────────────────────────
  inferenceLatency.add(res.timings.duration);

  // ── Checks ───────────────────────────────────────────────────────────────
  const ok = check(res, {
    'HTTP 200':               (r) => r.status === 200,
    'has outputs field':      (r) => {
      try { return JSON.parse(r.body).outputs !== undefined; } catch { return false; }
    },
    'output_label present':   (r) => {
      try {
        const body = JSON.parse(r.body);
        return body.outputs.some((o) => o.name === 'output_label');
      } catch { return false; }
    },
    'label in valid range':   (r) => {
      try {
        const body   = JSON.parse(r.body);
        const out    = body.outputs.find((o) => o.name === 'output_label');
        const label  = Array.isArray(out.data[0]) ? out.data[0][0] : out.data[0];
        return label >= 0 && label <= 6;
      } catch { return false; }
    },
  });

  inferenceOkRate.add(ok);
  if (!ok) {
    inferenceErrors.add(1);
    console.error(
      `[ref_id=${row.ref_id}] FAILED — status=${res.status} body=${res.body.substring(0, 200)}`
    );
  }

  // Optional: log every 100th request to stdout without spamming
  if (__ITER % 100 === 0) {
    try {
      const body  = JSON.parse(res.body);
      const out   = body.outputs.find((o) => o.name === 'output_label');
      const label = Array.isArray(out.data[0]) ? out.data[0][0] : out.data[0];
      console.log(
        `[iter=${__ITER} ref_id=${row.ref_id}] ` +
        `features=[${sats},${gcse},${asGrade}] ` +
        `→ predicted=${label} (${NUM_TO_GRADE[label] || '?'}) ` +
        `latency=${res.timings.duration.toFixed(1)}ms`
      );
    } catch (_) {
      console.log(`[iter=${__ITER}] Could not parse response`);
    }
  }

  // No sleep — single VU, throughput test; add sleep(0.1) here if rate-limiting needed
}

// ── Teardown: print summary stats ────────────────────────────────────────────
export function teardown () {
  console.log('=== Test complete: 1,000 inference requests sent to mathmodel ===');
}
